package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetIgnoreEmptyLines_DefaultTrue() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getIgnoreEmptyLines());  // fixed: DEFAULT.ignoreEmptyLines is false according to constructor call
    }

    @Test
    public void testGetIgnoreEmptyLines_ExplicitFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(false);
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLines_ExcelFormat() {
        CSVFormat format = CSVFormat.EXCEL;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLines_MysqlFormat() {
        CSVFormat format = CSVFormat.MYSQL;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLines_PostgresqlCsvFormat() {
        CSVFormat format = CSVFormat.POSTGRESQL_CSV;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLines_PostgresqlTextFormat() {
        CSVFormat format = CSVFormat.POSTGRESQL_TEXT;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLines_Rfc4180Format() {
        CSVFormat format = CSVFormat.RFC4180;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLines_TdfFormat() {
        CSVFormat format = CSVFormat.TDF;
        assertFalse(format.getIgnoreEmptyLines());  // fixed: TDF is based on DEFAULT which has ignoreEmptyLines = false
    }
}
